import{_ as a,o as r,c as l,a2 as o}from"./chunks/framework.Bjylvv1V.js";const b=JSON.parse('{"title":"아파트뱅크 이체","description":"","frontmatter":{},"headers":[],"relativePath":"guide/scenarios/bank-transfer.md","filePath":"guide/scenarios/bank-transfer.md","lastUpdated":null}'),e={name:"guide/scenarios/bank-transfer.md"};function n(s,t,i,d,h,c){return r(),l("div",null,[...t[0]||(t[0]=[o(`<h1 id="아파트뱅크-이체" tabindex="-1">아파트뱅크 이체 <a class="header-anchor" href="#아파트뱅크-이체" aria-label="Permalink to &quot;아파트뱅크 이체&quot;">​</a></h1><blockquote><p><strong>소요 시간</strong>: 건당 약 10분 | <strong>난이도</strong>: ★★★ | <strong>주기</strong>: 수시 (지출 발생 시)</p></blockquote><p>아파트 관리사무소에서 발생하는 지출(용역비, 수선비, 급여 등)을 아파트뱅크를 통해 안전하게 이체하는 프로세스입니다. 지출결의서 작성부터 결재 승인, 공인인증서 서명, 이체 결과 확인까지 단계별로 진행합니다.</p><h2 id="전체-흐름" tabindex="-1">전체 흐름 <a class="header-anchor" href="#전체-흐름" aria-label="Permalink to &quot;전체 흐름&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 지출결의서 작성     (3분)  → 지급처, 금액, 사유, 계좌 정보 입력</span></span>
<span class="line"><span>2. 출금전표 작성       (3분)  → 계정과목, 금액, 적요 입력</span></span>
<span class="line"><span>3. 출금전표 결재요청   (1분)  → 결재 담당자에게 승인 요청</span></span>
<span class="line"><span>4. 결재 승인 대기      (외부) → 결재권자 승인</span></span>
<span class="line"><span>5. 자금이체 실행       (2분)  → 공인인증서 서명 후 이체</span></span>
<span class="line"><span>6. 이체결과 확인       (1분)  → 이체 완료 여부 및 확인증 출력</span></span></code></pre></div><hr><h2 id="사전-확인" tabindex="-1">사전 확인 <a class="header-anchor" href="#사전-확인" aria-label="Permalink to &quot;사전 확인&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">이체 전 필수 확인</p><p>이체 실행 전 반드시 <strong>출금 계좌의 잔액</strong>을 확인하세요. 잔액 부족 시 이체가 실패하며, 수수료가 발생할 수 있습니다.</p></div><h3 id="체크리스트" tabindex="-1">체크리스트 <a class="header-anchor" href="#체크리스트" aria-label="Permalink to &quot;체크리스트&quot;">​</a></h3><ul><li>[ ] 지급처(수취인) 정보(은행, 계좌번호, 예금주)가 정확한가?</li><li>[ ] 이체 금액이 세금계산서·계약서와 일치하는가?</li><li>[ ] 출금 계좌에 잔액이 충분한가?</li><li>[ ] 결재권자가 결재 가능한 상태인가?</li><li>[ ] 공인인증서 유효기간이 남아 있는가?</li></ul><hr><h2 id="_1단계-지출결의서-작성-3분" tabindex="-1">1단계: 지출결의서 작성 (3분) <a class="header-anchor" href="#_1단계-지출결의서-작성-3분" aria-label="Permalink to &quot;1단계: 지출결의서 작성 (3분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 아파트뱅크 &gt; <a href="/bank/transfer.html">이체</a> &gt; 지출결의서작성 (BANK1200)</p></blockquote><p>지출의 목적과 내용을 기록하는 공식 결의 문서를 작성합니다.</p><h3 id="절차" tabindex="-1">절차 <a class="header-anchor" href="#절차" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>지출결의서작성 화면 진입</li><li>아래 항목 입력:</li></ol><table tabindex="0"><thead><tr><th>입력 항목</th><th>설명</th><th>예시</th></tr></thead><tbody><tr><td><strong>결의일자</strong></td><td>결의하는 날짜</td><td>2026-03-03</td></tr><tr><td><strong>지급처</strong></td><td>수취인 이름 또는 업체명</td><td>○○청소용역(주)</td></tr><tr><td><strong>지급 금액</strong></td><td>이체할 총금액</td><td>1,500,000원</td></tr><tr><td><strong>지급 사유</strong></td><td>이체 목적</td><td>3월 청소용역비</td></tr><tr><td><strong>출금 계좌</strong></td><td>출금할 단지 계좌</td><td>관리비 통장</td></tr><tr><td><strong>입금 계좌</strong></td><td>수취인 계좌 정보</td><td>은행·계좌번호·예금주</td></tr></tbody></table><ol start="3"><li><strong>저장</strong> 클릭</li></ol><div class="tip custom-block"><p class="custom-block-title">자주 사용하는 지급처</p><p>매월 반복 지급하는 용역업체는 수취인 정보를 미리 등록해 두면 빠르게 불러올 수 있습니다.</p></div><hr><h2 id="_2단계-출금전표-작성-3분" tabindex="-1">2단계: 출금전표 작성 (3분) <a class="header-anchor" href="#_2단계-출금전표-작성-3분" aria-label="Permalink to &quot;2단계: 출금전표 작성 (3분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 아파트뱅크 &gt; <a href="/bank/transfer.html">이체</a> &gt; 온라인출금전표작성 (BANK1070)</p></blockquote><p>이체 금액을 회계 계정과목에 연결하는 출금전표를 작성합니다.</p><h3 id="절차-1" tabindex="-1">절차 <a class="header-anchor" href="#절차-1" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>온라인출금전표작성 화면 진입</li><li>앞서 작성한 <strong>지출결의서</strong> 불러오기</li><li>아래 항목 입력:</li></ol><table tabindex="0"><thead><tr><th>입력 항목</th><th>설명</th><th>예시</th></tr></thead><tbody><tr><td><strong>계정과목</strong></td><td>지출 항목 분류</td><td>관리용역비</td></tr><tr><td><strong>금액</strong></td><td>지출결의서 금액과 동일</td><td>1,500,000원</td></tr><tr><td><strong>적요</strong></td><td>거래 내용 요약</td><td>3월 청소용역비 지급</td></tr><tr><td><strong>부서</strong></td><td>해당 부서 (단지에 따라 상이)</td><td>관리팀</td></tr></tbody></table><ol start="4"><li><strong>저장</strong> 클릭</li></ol><h3 id="자주-사용하는-계정과목" tabindex="-1">자주 사용하는 계정과목 <a class="header-anchor" href="#자주-사용하는-계정과목" aria-label="Permalink to &quot;자주 사용하는 계정과목&quot;">​</a></h3><table tabindex="0"><thead><tr><th>계정과목</th><th>용도</th></tr></thead><tbody><tr><td>관리용역비</td><td>청소·경비·소독 등 용역 대금</td></tr><tr><td>수선유지비</td><td>시설 수선·보수 비용</td></tr><tr><td>인건비</td><td>직원 급여 (아파트뱅크 이체 시)</td></tr><tr><td>소모품비</td><td>사무용품·소모품 구매</td></tr><tr><td>보험료</td><td>단지 보험 납부</td></tr></tbody></table><hr><h2 id="_3단계-출금전표-결재요청-1분" tabindex="-1">3단계: 출금전표 결재요청 (1분) <a class="header-anchor" href="#_3단계-출금전표-결재요청-1분" aria-label="Permalink to &quot;3단계: 출금전표 결재요청 (1분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 아파트뱅크 &gt; <a href="/bank/transfer.html">이체</a> &gt; 출금전표결재요청 (BANK1080)</p></blockquote><p>작성한 출금전표를 결재권자에게 승인 요청합니다.</p><h3 id="절차-2" tabindex="-1">절차 <a class="header-anchor" href="#절차-2" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>출금전표결재요청 화면 진입</li><li>결재요청할 전표 선택</li><li>결재선 확인 (단지 설정에 따라 1단계 또는 다단계 결재)</li><li><strong>결재요청</strong> 클릭</li></ol><div class="warning custom-block"><p class="custom-block-title">결재 승인 전 이체 불가</p><p>이체는 <strong>결재 승인 완료 후에만</strong> 실행할 수 있습니다. 결재 승인 없이 이체를 시도하면 진행되지 않습니다.</p></div><hr><h2 id="_4단계-결재-승인-대기-외부-절차" tabindex="-1">4단계: 결재 승인 대기 (외부 절차) <a class="header-anchor" href="#_4단계-결재-승인-대기-외부-절차" aria-label="Permalink to &quot;4단계: 결재 승인 대기 (외부 절차)&quot;">​</a></h2><p>결재권자(관리소장, 입주자대표 등)가 결재를 승인합니다. 이 단계는 시스템 외부(또는 결재권자 화면)에서 진행됩니다.</p><ul><li>결재 완료 여부는 아파트뱅크 결재 목록에서 확인합니다.</li><li>긴급 이체가 필요한 경우 결재권자에게 직접 연락하여 신속 승인을 요청하세요.</li></ul><hr><h2 id="_5단계-자금이체-실행-2분" tabindex="-1">5단계: 자금이체 실행 (2분) <a class="header-anchor" href="#_5단계-자금이체-실행-2분" aria-label="Permalink to &quot;5단계: 자금이체 실행 (2분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 아파트뱅크 &gt; <a href="/bank/transfer.html">이체</a> &gt; 자금이체실행 (BANK1090)</p></blockquote><p>결재가 승인된 전표를 공인인증서로 서명하여 실제 이체를 실행합니다.</p><h3 id="절차-3" tabindex="-1">절차 <a class="header-anchor" href="#절차-3" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>자금이체실행 화면 진입</li><li><strong>승인 완료</strong> 상태의 전표 확인</li><li>이체 정보 최종 확인: <ul><li>출금 계좌 / 입금 계좌</li><li>이체 금액</li><li>수취인 예금주명</li></ul></li><li><strong>공인인증서 서명</strong> 실행</li><li>이체 <strong>실행</strong> 클릭</li></ol><h3 id="공인인증서-서명-시-주의사항" tabindex="-1">공인인증서 서명 시 주의사항 <a class="header-anchor" href="#공인인증서-서명-시-주의사항" aria-label="Permalink to &quot;공인인증서 서명 시 주의사항&quot;">​</a></h3><ul><li>공인인증서의 <strong>유효기간</strong>을 사전에 확인하세요.</li><li>인증서 비밀번호를 여러 번 틀리면 잠길 수 있습니다.</li><li>인증서 갱신이 필요한 경우 거래 은행에서 갱신 후 진행하세요.</li></ul><div class="danger custom-block"><p class="custom-block-title">이체 실행은 취소 불가</p><p>이체 실행 후에는 즉시 은행으로 전송됩니다. 계좌번호, 금액, 수취인을 <strong>반드시 실행 전에</strong> 다시 한번 확인하세요.</p></div><hr><h2 id="_6단계-이체결과-확인-1분" tabindex="-1">6단계: 이체결과 확인 (1분) <a class="header-anchor" href="#_6단계-이체결과-확인-1분" aria-label="Permalink to &quot;6단계: 이체결과 확인 (1분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 아파트뱅크 &gt; <a href="/bank/transfer.html">이체</a> &gt; 이체결과/이체확인증 (BANK1030)</p></blockquote><p>이체가 정상적으로 완료되었는지 확인하고, 필요 시 이체확인증을 출력합니다.</p><h3 id="절차-4" tabindex="-1">절차 <a class="header-anchor" href="#절차-4" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>이체결과/이체확인증 화면 진입</li><li>해당 이체 건 조회</li><li><strong>이체 상태</strong> 확인: <ul><li><strong>완료</strong>: 정상 이체</li><li><strong>실패</strong>: 이체 오류 (사유 확인 필요)</li><li><strong>처리 중</strong>: 은행 처리 중 (잠시 후 재확인)</li></ul></li><li>필요 시 <strong>이체확인증 출력</strong> (세금계산서 첨부용 등)</li></ol><h3 id="이체-실패-시-조치" tabindex="-1">이체 실패 시 조치 <a class="header-anchor" href="#이체-실패-시-조치" aria-label="Permalink to &quot;이체 실패 시 조치&quot;">​</a></h3><table tabindex="0"><thead><tr><th>실패 사유</th><th>조치</th></tr></thead><tbody><tr><td>수취 계좌 오류</td><td>지급처 계좌번호 재확인 후 재이체</td></tr><tr><td>잔액 부족</td><td>출금 계좌에 입금 후 재이체</td></tr><tr><td>은행 시스템 오류</td><td>잠시 후 재시도 또는 은행 문의</td></tr><tr><td>한도 초과</td><td>이체 한도 확인 및 은행에 한도 상향 요청</td></tr></tbody></table><hr><h2 id="이체-후-전표-확인" tabindex="-1">이체 후 전표 확인 <a class="header-anchor" href="#이체-후-전표-확인" aria-label="Permalink to &quot;이체 후 전표 확인&quot;">​</a></h2><p>이체 완료 후 회계 전표가 자동 생성된 경우 내용을 확인합니다.</p><blockquote><p><strong>메뉴 경로</strong>: 회계 &gt; <a href="/acct/voucher.html">전표관리</a> &gt; 전표입력 (ACCT2010)</p></blockquote><p>아파트뱅크와 회계 모듈이 연동된 경우 이체 내역이 자동으로 전표에 반영될 수 있습니다. 자동 생성된 전표의 계정과목과 적요가 정확한지 확인하세요.</p><hr><h2 id="자주-발생하는-문제" tabindex="-1">자주 발생하는 문제 <a class="header-anchor" href="#자주-발생하는-문제" aria-label="Permalink to &quot;자주 발생하는 문제&quot;">​</a></h2><h3 id="결재요청-후-이체-버튼이-안-눌려요" tabindex="-1">결재요청 후 이체 버튼이 안 눌려요 <a class="header-anchor" href="#결재요청-후-이체-버튼이-안-눌려요" aria-label="Permalink to &quot;결재요청 후 이체 버튼이 안 눌려요&quot;">​</a></h3><p><strong>원인</strong>: 결재 승인이 아직 완료되지 않은 상태입니다. <strong>해결</strong>: 결재권자에게 승인 완료를 확인하거나, 결재 목록에서 승인 상태를 확인하세요. <strong>결재 완료 후에만</strong> 이체 실행이 활성화됩니다.</p><h3 id="공인인증서-오류가-나요" tabindex="-1">공인인증서 오류가 나요 <a class="header-anchor" href="#공인인증서-오류가-나요" aria-label="Permalink to &quot;공인인증서 오류가 나요&quot;">​</a></h3><p><strong>원인</strong>: 인증서 만료, 비밀번호 오류, 인증서 미설치 등입니다. <strong>해결</strong>: 인증서 유효기간을 확인하고 만료된 경우 거래 은행에서 갱신하세요. 비밀번호를 5회 이상 틀리면 인증서가 잠기므로 주의하세요.</p><h3 id="이체가-실패했는데-잔액은-빠져나갔어요" tabindex="-1">이체가 실패했는데 잔액은 빠져나갔어요 <a class="header-anchor" href="#이체가-실패했는데-잔액은-빠져나갔어요" aria-label="Permalink to &quot;이체가 실패했는데 잔액은 빠져나갔어요&quot;">​</a></h3><p><strong>원인</strong>: 이체 처리 중 오류로 출금 후 환불이 지연되는 경우입니다. <strong>해결</strong>: 이체결과(BANK1030)에서 상태를 확인하세요. 은행 측에서 통상 1영업일 내에 자동 환불됩니다. 지연될 경우 거래 은행 및 아파트뱅크 고객센터에 문의하세요.</p><h3 id="계좌번호를-잘못-입력했어요" tabindex="-1">계좌번호를 잘못 입력했어요 <a class="header-anchor" href="#계좌번호를-잘못-입력했어요" aria-label="Permalink to &quot;계좌번호를 잘못 입력했어요&quot;">​</a></h3><p><strong>원인</strong>: 수취인 계좌 정보 오입력입니다. <strong>해결</strong>: 이체 전에 발견한 경우 결의서/전표를 수정하면 됩니다. 이체 <strong>완료 후</strong>에 잘못된 계좌로 보낸 경우 즉시 거래 은행에 연락하여 착오 송금 반환 절차를 진행하세요.</p><hr><h2 id="관련-메뉴" tabindex="-1">관련 메뉴 <a class="header-anchor" href="#관련-메뉴" aria-label="Permalink to &quot;관련 메뉴&quot;">​</a></h2><ul><li><a href="/bank/transfer.html">지출결의서작성</a> - 이체 결의 문서 작성 (BANK1200)</li><li><a href="/bank/transfer.html">온라인출금전표작성</a> - 계정과목 연결 전표 작성 (BANK1070)</li><li><a href="/bank/transfer.html">출금전표결재요청</a> - 결재권자 승인 요청 (BANK1080)</li><li><a href="/bank/transfer.html">자금이체실행</a> - 공인인증서 서명 및 이체 실행 (BANK1090)</li><li><a href="/bank/transfer.html">이체결과/이체확인증</a> - 이체 완료 확인 및 출력 (BANK1030)</li><li><a href="/bank/transaction.html">은행거래내역</a> - 이체 후 통장 내역 확인 (BANK0010)</li><li><a href="/guide/scenarios/expense-voucher.html">지출 전표 입력</a> - 이체 없이 전표만 입력하는 경우</li><li><a href="/guide/scenarios/payroll.html">급여 처리</a> - 급여 이체 시 이 메뉴 활용</li></ul>`,75)])])}const p=a(e,[["render",n]]);export{b as __pageData,p as default};
